-- file: schemas/0231_theme_pref.sql
-- Per-user theme preference (issue #532): 'dark' | 'light' | 'system'. Default 'dark' so
-- every existing user keeps today's dark-only experience until they opt into the Parchment
-- light theme; new rows default dark too. A non-null default backfills existing rows, so the
-- preference is live for current users immediately. Rides the cached users profile (ADR-0014)
-- alongside avatar_key / show_team_trends — read in hooks.server.ts (and resolved onto <html>
-- at SSR via transformPageChunk) and busted on write in /api/profile.
alter table public.users
  add column if not exists theme_pref text not null default 'dark';

-- Named check so the pgTAP can assert it and an invalid value is rejected at the DB. Drop
-- first so the migration stays idempotent if the column already existed pre-constraint.
alter table public.users
  drop constraint if exists users_theme_pref_check;
alter table public.users
  add constraint users_theme_pref_check check (theme_pref in ('dark', 'light', 'system'));
